/**
 * Fetches current user information from Nextcloud OCS API.
 */
type Nextcloud = {
  baseUrl: string;
  userId: string;
  token: string;
};

export async function main(ncResource: Nextcloud, userId: string): Promise<any> {
  const baseUrl = ncResource.baseUrl.replace(/\/$/, "");
  const response = await fetch(`${baseUrl}/ocs/v2.php/cloud/users/${userId}?format=json`, {
    method: "GET",
    headers: {
      Authorization: `Basic ${btoa(`${ncResource.userId}:${ncResource.token}`)}`,
      "OCS-APIRequest": "true",
      Accept: "application/json",
    },
  });

  if (!response.ok) {
    const body = await response.text();
    throw new Error(
      `Failed to fetch /ocs/v2.php/cloud/user: ${response.status} ${response.statusText} - ${body}`,
    );
  }

  return (await response.json()).ocs.data;
}

import axios from "axios";
import XlsxPopulate from "xlsx-populate";
import Papa from 'papaparse';

type FormAnswer = {
  id: number;
  text: string;
  fileId: number | undefined;
  questionId: number;
  questionName: string;
};

export async function main(
  nextcloud: RT.Nextcloud,
  templatePath: string,
  outputPath: string,
  formAnswers: FormAnswer[],
  imageAnalysis: string[],
  datetime: string,
  location: string,
  displayName: string,
) {
  const getRes = await axios.get(
    `${nextcloud.baseUrl}/remote.php/dav/files/${nextcloud.userId}/${templatePath}`,
    {
      auth: {
        username: nextcloud.userId,
        password: nextcloud.token,
      },
      responseType: "arraybuffer",
    },
  );
  if (getRes.status !== 200) {
    throw new Error(getRes.statusText);
  }

  const workbook = await XlsxPopulate.fromDataAsync(
    Buffer.from(getRes.data as ArrayBuffer),
  );

  const reportSheet = workbook
    .sheets()
    .find((s) => s.name() === "Report");
  const calculationSheet = workbook
    .sheets()
    .find((s) => s.name() === "Calculation");
  if (!reportSheet || !calculationSheet) {
    const available = workbook.sheets().map((s) => s.name()).join(", ");
    throw new Error(`Report or calculation sheet not found. Available: ${available}`);
  }

  let conversionRate = 1;
  const transportationMeans = new Set<string>();

  // Setup datetime parts and ensure the array has 4 parts
  const datetimeParts = datetime.split(",").map((part) => part.trim());
  while (datetimeParts.length < 4) {
    datetimeParts.push("Unknown");
  }
  while (datetimeParts.length > 4) {
    datetimeParts.pop();
  }
  const [departureDate, departureTime, returnDate, returnTime] = datetimeParts;
  reportSheet.cell("A10").value(departureDate);
  reportSheet.cell("B10").value(departureTime);
  reportSheet.cell("C10").value(returnDate);
  reportSheet.cell("D10").value(returnTime);

  // Add location to the report sheet
  reportSheet.cell("A7").value(location);

  // Add display name
  reportSheet.cell("A5").value(displayName);

  // Iterate over the form answers
  for (const formAnswer of formAnswers) {
    const questionName = formAnswer.questionName;
    const answer = formAnswer.text;
    switch (questionName) {
      case "name":
        reportSheet.cell("A5").value(`${displayName}, ${answer}`);
        break;
      case "visted":
        reportSheet.cell("E7").value(answer);
        break;
      case "purpose":
        reportSheet.cell("H7").value(answer);
        break;
      case "km":
        if (Number(answer) > 0) {
          reportSheet.cell("E20").value(Number(answer));
          transportationMeans.add("car");
        }
        break;
      case "advance_payment":
        if (Number(answer) > 0) {
          reportSheet.cell("E40").value(Number(answer));
        }
        break;
      case "exchange_rate":
        conversionRate = Number(answer);
        reportSheet.cell("H5").value(`${conversionRate} EUR`);
        break;
    }

  }
  let counter = 1;
  // Iterate over the image analysis CSV files
  for (const imageCSV of imageAnalysis) {
    const data = Papa.parse<string[]>(imageCSV, { skipEmptyLines: true });
    for (const rawRow of data.data) {
      const row = normalizeImageAnalysisRow(rawRow);
      if (!row) continue;
      if (row[0] === "purchase_name") {
        continue;
      }
      const purchaseName = row[0];
      const category = row[1];
      const totalPriceForeignCurrency = Number(row[2]);
      const currency = row[4];
      const exchangeRate = currency === "EUR" ? 1 : conversionRate;
      const totalPrice = totalPriceForeignCurrency * exchangeRate;
      const potentialTax = row[3];
      // Ensure that the tax is a number
      const tax = !potentialTax
        ? 0
        : potentialTax.includes("%")
          ? (() => {
              // `totalPrice` is gross (incl. tax). Extract tax portion from gross: gross * r/(1+r)
              const r = Number(potentialTax.replace("%", "")) / 100;
              if (!Number.isFinite(r) || r <= 0) return 0;
              return totalPrice * (r / (1 + r));
            })()
          : Number(potentialTax);
      counter++;
      if (counter > 100) {
        throw new Error("Too many rows to process");
      }
      calculationSheet.cell(`A${counter}`).value(purchaseName);
      calculationSheet.cell(`B${counter}`).value(category);
      calculationSheet.cell(`C${counter}`).value(totalPrice);
      calculationSheet.cell(`D${counter}`).value(tax);
      calculationSheet.cell(`F${counter}`).value(currency);
      calculationSheet.cell(`G${counter}`).value(totalPriceForeignCurrency);
      transportationMeans.add(category);
    }
  }
  console.log(transportationMeans)

  // Add transportation means to the report sheet
  if (transportationMeans.has("plane")) {
    reportSheet.cell("F9").value("X");
  }
  if (transportationMeans.has("public transport")) {
    reportSheet.cell("F10").value("X");
  }
  if (transportationMeans.has("car rental")) {
    reportSheet.cell("F11").value("X");
  }
  if (transportationMeans.has("car")) {
    reportSheet.cell("K9").value("X");
  }
  if (transportationMeans.has("taxi")) {
    reportSheet.cell("K10").value("X");
  }

  // Put the current date into J3 in the report sheet
  const now = new Date();
  const formattedDate = `${now.getDate().toString().padStart(2, "0")}.${(now.getMonth() + 1).toString().padStart(2, "0")}.${now.getFullYear()}`;
  reportSheet.cell("J3").value(formattedDate);
  // Get the month spelled out in English
  const monthNames = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"
  ];
  reportSheet.cell("L3").value(monthNames[now.getMonth()]);


  const out = await workbook.outputAsync();

  try {
    const putRes = await axios.request({
      method: "PUT",
      url: `/remote.php/dav/files/${nextcloud.userId}/${outputPath}`,
      baseURL: nextcloud.baseUrl,
      data: out,
      headers: {
        Authorization: `Basic ${btoa(`${nextcloud.userId}:${nextcloud.token}`)}`,
        "Content-Type":
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      },
      maxBodyLength: Infinity,
      maxContentLength: Infinity,
    });
    return outputPath;
  } catch (e: unknown) {
    console.log(e);
    throw e instanceof Error ? e : new Error(String(e));
  }
}

function normalizeImageAnalysisRow(rawFields: unknown[]): [string, string, string, string, string] | null {
  const fields = rawFields.map((v) => String(v ?? "").trim());
  while (fields.length > 0 && fields[fields.length - 1] === "") fields.pop();

  if (fields.length === 0) return null;

  // Common failure modes:
  // - Missing tax column: [name, category, amount, currency]
  // - Commas inside purchase_name: [name_part1, name_part2, ..., category, amount, tax, currency]
  let f = fields.slice();

  if (f.length > 5) {
    const mergedName = f.slice(0, f.length - 4).join(", ").trim();
    f = [mergedName, ...f.slice(f.length - 4)];
  }

  // Ensure that the length is at least 3
  if (f.length < 3) {
    return null;
  }
  // If the length is 3, add a missing tax column
  if (f.length === 3) {
    f = [f[0], f[1], f[2], "0"];
  }
  // If the length is 4, add a missing currency column
  if (f.length === 4) {
    f = [f[0], f[1], f[2], f[3], "EUR"];
  }

  // If the "currency" ended up in column 4 and tax is missing, fix it.
  const looksLikeCurrency = (s: string) => /^[A-Z]{3}$/.test(s.trim());
  if (looksLikeCurrency(f[3])) {
    f = [f[0], f[1], f[2], "0", f[3]];
  }

  // Ensure exactly 5 columns.
  if (f.length > 5) f = f.slice(0, 5);

  return [f[0], f[1], f[2], f[3], f[4]];
}

import { createClient } from "webdav";

/**
 * Resolves a Nextcloud fileid from a path under the user's files root.
 * Use the same path shape as `get-nextcloud-path-by-fileid.ts` returns, e.g. `/Documents/file.pdf`.
 */
export async function main(
  ncResource: RT.Nextcloud,
  path: string
): Promise<string> {

  const baseUrl = ncResource.baseUrl.replace(/\/$/, "");
  // Same root as list-nextcloud-files.ts. User id is encoded here only once;
  // the webdav client runs encodePath() on remote paths — do not pre-encode segments
  // or emails like user@host become user%2540host and PROPFIND returns 404.
  const davBaseUrl = `${baseUrl}/remote.php/dav/files/${encodeURIComponent(ncResource.userId)}`;
  const client = createClient(davBaseUrl, {
    username: ncResource.userId,
    password: ncResource.token,
  });

  const davPath = path;
  const propfindXml = buildPropfindFileIdXml();
  const rawResponse = await client.customRequest(davPath, {
    method: "PROPFIND",
    data: propfindXml,
    headers: {
      "Content-Type": "text/xml; charset=utf-8",
      Accept: "application/xml, text/xml",
      Depth: "0",
    },
    responseType: "text",
  });

  const responseXml = await rawResponse.text();
  if (!rawResponse.ok) {
    throw new Error(
      `PROPFIND failed (HTTP ${rawResponse.status}) for path "${path}"`
    );
  }

  const fileid = extractFileIdFromPropfindResponse(responseXml);
  if (!fileid) {
    throw new Error(`Could not resolve fileid for path "${path}"`);
  }

  return fileid;
}


function buildPropfindFileIdXml(): string {
  return `<?xml version="1.0" encoding="UTF-8"?>
<d:propfind xmlns:d="DAV:" xmlns:oc="http://owncloud.org/ns">
  <d:prop>
    <oc:fileid/>
  </d:prop>
</d:propfind>`;
}

function extractFileIdFromPropfindResponse(xml: string): string | null {
  const m = xml.match(/<oc:fileid>([^<]*)<\/oc:fileid>/);
  const id = m?.[1]?.trim();
  return id && /^\d+$/.test(id) ? id : null;
}

import axios from "axios";

/**
 * Assigns a collaborative (system) tag to a file via WebDAV.
 *
 * `fileId` and `tagId` are the numeric ids from Nextcloud (e.g. from DAV PROPFIND or other scripts).
 */
export async function main(
  ncResource: RT.Nextcloud,
  fileId: string | number,
  tagId: string | number
) {

  const base = ncResource.baseUrl.replace(/\/$/, "");
  const response = await axios.put(
    `${base}/remote.php/dav/systemtags-relations/files/${fileId}/${tagId}`,
    "",
    {
      auth: {
        username: ncResource.userId,
        password: ncResource.token,
      },
      headers: { "Content-Type": "text/xml" },
      validateStatus: () => true,
    }
  );

  if (response.status === 201) {
    return { fileId, tagId, alreadyAssigned: false };
  }
  if (response.status === 409) {
    return { fileId, tagId, alreadyAssigned: true };
  }

  throw new Error(`Failed to assign tag (HTTP ${response.status})${response.data}`);
}

// import * as wmill from "windmill-client"

export async function main(triggerUserId: string, form: any, lineManager: string) {
  const result = [triggerUserId]
  // Adds line manager from form if exists
  const lineManagerForm = form.submission.answers.filter((e) => e.questionName === "line_manager")
  if (lineManagerForm.length > 0) {
    result.push(lineManagerForm[0].text)
  }
  // Only add line manager if not an empty string
  if (lineManager !== "") {
    result.push(lineManager)
  }
  return result
}
